
CREATE TABLE especies_vegetales (
    id INT PRIMARY KEY,
    nombre_comun VARCHAR(255),
    nombre_cientifico VARCHAR(255),
    descripcion_morfológica TEXT,
    tallos TEXT,
    hojas TEXT,
    flores TEXT,
    frutos TEXT,
    raíz TEXT,
    usos TEXT,
    tipo_de_propagación TEXT,
    interacciones_con_otras_especies TEXT,
    lugar_de_origen TEXT,
    rusticidad TEXT,
    riego_requerido TEXT,
    sustrato_recomendado TEXT,
    adaptabilidad_climática TEXT,
    radiación_solar_requerida TEXT,
    distancia_de_plantación TEXT,
    densidad_de_plantación_por_m TEXT,
    mantenimiento TEXT
);

